import{_ as t,o as r,c as s,a2 as i}from"./chunks/framework.D2pTuMig.js";const m=JSON.parse('{"title":"Paiement des Revenus","description":"","frontmatter":{"title":"Paiement des Revenus"},"headers":[],"relativePath":"docs/fr/publishers/payouts.md","filePath":"docs/fr/publishers/payouts.md"}'),o={name:"docs/fr/publishers/payouts.md"};function a(n,e,l,d,u,c){return r(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="gestion-des-revenus-et-paiements" tabindex="-1">Gestion des Revenus et Paiements <a class="header-anchor" href="#gestion-des-revenus-et-paiements" aria-label="Permalink to &quot;Gestion des Revenus et Paiements&quot;">​</a></h1><p>Suivez vos gains en temps réel et optimisez votre trésorerie pour éviter les frais.</p><h2 id="suivi-du-p-l-wallet" tabindex="-1">Suivi du P&amp;L (Wallet) <a class="header-anchor" href="#suivi-du-p-l-wallet" aria-label="Permalink to &quot;Suivi du P&amp;L (Wallet)&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Vos revenus sont visibles en temps réel sur la plateforme.</p><p>Consultez à tout moment votre <strong>Solde Disponible</strong> = <em>(Revenus validés) - (Retraits effectués)</em>.</p></div><h3 id="quand-mes-revenus-deviennent-disponibles" tabindex="-1">Quand mes revenus deviennent disponibles ? <a class="header-anchor" href="#quand-mes-revenus-deviennent-disponibles" aria-label="Permalink to &quot;Quand mes revenus deviennent disponibles ?&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">INFO</p><p><strong>📅 Timeline de validation</strong></p><ol><li><strong>Campagne distribuée :</strong> Le jour où vous confirmez la distribution (lot expédié, volumes déclarés).</li><li><strong>Délai de protection (30 jours) :</strong> Votre revenu reste en <em>attente</em> pendant 30 jours → permet de détecter les anomalies (cartons perdus, campagne interrompue).</li><li><strong>✅ Revenu validé :</strong> Après 30 jours sans incident, le montant passe en <em>Solde Disponible</em> et peut être retiré.</li></ol></div><div class="tip custom-block"><p class="custom-block-title">Cas normal (pas de problème)</p><p>J1 : Distribution confirmée → J31 : Revenu devient disponible → Vous pouvez retirer.</p></div><div class="warning custom-block"><p class="custom-block-title">Anomalie détectée pendant les 30 jours</p><p>Ex : cartons perdus, campagne bloquée → Nous vous contactons pour résoudre. Le délai peut être prolongé jusqu&#39;à règlement.</p></div><h2 id="politique-de-retrait-et-frais" tabindex="-1">Politique de Retrait et Frais <a class="header-anchor" href="#politique-de-retrait-et-frais" aria-label="Permalink to &quot;Politique de Retrait et Frais&quot;">​</a></h2><p>Nous encourageons le regroupement des paiements pour limiter les frictions administratives.</p><h3 id="structure-tarifaire-selon-votre-offre" tabindex="-1">Structure Tarifaire selon votre Offre <a class="header-anchor" href="#structure-tarifaire-selon-votre-offre" aria-label="Permalink to &quot;Structure Tarifaire selon votre Offre&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Offre</th><th>Frais de retrait</th></tr></thead><tbody><tr><td>🟡 Starter</td><td>1er retrait/an : <strong>GRATUIT</strong> · Suivants : <strong>5%</strong> (ex : 1 000€ retirés → 950€ reçus)</td></tr><tr><td>🟢 Plateforme &amp; Managed</td><td><strong>GRATUIT</strong> — tous les retraits, illimité</td></tr></tbody></table><blockquote><p><strong>Pas sûr de votre offre ?</strong> Vérifiez sur votre espace compte → Abonnement, ou consultez la <a href="/handbook/docs/fr/publishers/pricing.html">page Pricing</a>.</p></blockquote><h3 id="delais-de-paiement" tabindex="-1">Délais de Paiement <a class="header-anchor" href="#delais-de-paiement" aria-label="Permalink to &quot;Délais de Paiement&quot;">​</a></h3><div class="gi-value-grid"><div class="gi-value-card"><strong>📄 Pré-requis</strong><p>Soumettez votre <strong>facture conforme</strong> avec la demande de retrait. Sans facture valide, le paiement ne peut pas être traité.</p></div><div class="gi-value-card"><strong>🏦 Délai de Paiement</strong><p><strong>30 jours fin de mois</strong> après validation de votre demande.<br>Ex : demande validée en mars → paiement avant fin avril.</p></div><div class="gi-value-card"><strong>💰 Montant Minimum</strong><p><strong>Pas de minimum imposé.</strong> Retirez dès que vous avez un solde disponible.</p></div></div><h3 id="actions-requises-pour-crediter-votre-wallet" tabindex="-1">Actions requises pour créditer votre Wallet <a class="header-anchor" href="#actions-requises-pour-crediter-votre-wallet" aria-label="Permalink to &quot;Actions requises pour créditer votre Wallet&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">Vos revenus ne se créditent pas automatiquement</p><p>Le solde Wallet n&#39;est mis à jour qu&#39;<strong>après une action manuelle de votre part</strong> selon le format :</p></div><table tabindex="0"><thead><tr><th>Format</th><th>Action requise</th><th>Où sur la plateforme</th></tr></thead><tbody><tr><td>📦 Insertion Colis</td><td>Déclarez les volumes chaque <strong>lundi ou mardi</strong></td><td>Mes Campagnes → campagne → Déclarer le volume</td></tr><tr><td>📧 Emailing (Dédié ou Display)</td><td>Cliquez sur <strong>&quot;Valider la diffusion&quot;</strong> après l&#39;envoi</td><td>Mes Campagnes → campagne → Valider la diffusion</td></tr></tbody></table><h2 id="comment-eviter-les-frais-de-5-offre-starter-uniquement" tabindex="-1">Comment éviter les frais de 5% ? <em>(Offre Starter uniquement)</em> <a class="header-anchor" href="#comment-eviter-les-frais-de-5-offre-starter-uniquement" aria-label="Permalink to &quot;Comment éviter les frais de 5% ? *(Offre Starter uniquement)*&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>Option A : Le &quot;Cumul&quot;</strong><p>Laissez vos revenus s&#39;accumuler sur votre cagnotte. En espaçant vos retraits, retirez vos revenus une fois par an — un retrait groupé <strong>sans frais</strong>.</p></div><div class="gi-value-card"><strong>Option B : Le Réinvestissement</strong><p>Utilisez votre solde pour financer vos propres campagnes d&#39;acquisition (Insertion Colis ou Emailing). 1€ gagné = 1€ réinvesti en trafic, sans friction bancaire.</p></div></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p><strong>💡 Pourquoi cette politique ?</strong></p><ol><li><strong>Réduction de l&#39;Admin :</strong> Limiter le volume de petits virements nous permet de maintenir des coûts de plateforme bas.</li><li><strong>Sécurité (Buffer) :</strong> Ce délai de trésorerie sécurise les fonds en cas d&#39;impayés annonceurs, vous garantissant d&#39;être payé même si l&#39;annonceur a du retard.</li></ol></div><h2 id="⚠️-regle-d-expiration-des-fonds" tabindex="-1">⚠️ Règle d&#39;expiration des fonds <a class="header-anchor" href="#⚠️-regle-d-expiration-des-fonds" aria-label="Permalink to &quot;⚠️ Règle d&#39;expiration des fonds&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">Fonds expirés après 12 mois d&#39;inactivité</p><p>Si vous ne vous connectez pas <strong>ET</strong> ne retirez pas vos revenus pendant <strong>12 mois consécutifs</strong>, les fonds disponibles expirent et sont définitivement acquis à getinside.</p><p><strong>Comment éviter cela :</strong> connectez-vous régulièrement, ou activez les notifications de solde sur votre espace compte.</p></div><h2 id="comment-effectuer-un-retrait" tabindex="-1">Comment effectuer un retrait ? <a class="header-anchor" href="#comment-effectuer-un-retrait" aria-label="Permalink to &quot;Comment effectuer un retrait ?&quot;">​</a></h2><ol><li>Connectez-vous à votre espace distributeur sur <strong>getinside.io</strong></li><li>Accédez à <strong>Mon Compte → Wallet / P&amp;L</strong></li><li>Vérifiez votre <strong>Solde Disponible</strong> (uniquement ce montant est retirable)</li><li>Cliquez sur <strong>Demander un virement</strong></li><li>Renseignez le montant souhaité et confirmez votre IBAN</li><li>Validez la demande → vous recevrez un email de confirmation</li></ol><p><strong>Délai :</strong> 30 jours fin de mois après validation de votre demande et réception de votre facture.</p><h2 id="en-cas-de-probleme" tabindex="-1">En cas de problème <a class="header-anchor" href="#en-cas-de-probleme" aria-label="Permalink to &quot;En cas de problème&quot;">​</a></h2><p>Votre solde ne correspond pas à vos attentes ? Un retrait tarde ?</p><p>→ Consultez le guide <a href="/handbook/docs/fr/faq/troubleshooting-distributors.html">Problèmes Wallet &amp; Paiements</a> pour les cas fréquents et leur solution.</p><hr><p><strong>Prochaine étape :</strong> Boostez vos revenus avec le <a href="/handbook/docs/fr/publishers/score-distributor.html">Score Distributeur</a> — plus votre score est élevé, plus vous recevez de campagnes.</p>',31)])])}const v=t(o,[["render",a]]);export{m as __pageData,v as default};
